content.query:
let MedianMs = toscalar(
    app('{NodeApiAppInsights:name}').customEvents
    | where timestamp {TimeRange}
    | where name == "TrusteeMatchVerificationResolved"
    | where customDimensions.action == "approve"
    | extend resolutionMs = todouble(customMeasurements.resolutionMs)
    | summarize percentile(resolutionMs, 50)
);
print Result = case(
    isnull(MedianMs), "No tasks resolved",
    MedianMs < 3600000, strcat(round(MedianMs / 60000, 1), " minutes"),
    MedianMs < 86400000, strcat(round(MedianMs / 3600000, 1), " hours"),
    strcat(round(MedianMs / 86400000, 1), " days")
)
